{"blocks":[{"key":"10pbp","text":"Wash Buffer (WB):","type":"unstyled","depth":0,"inlineStyleRanges":[{"style":"bold","offset":0,"length":17}],"entityRanges":[],"data":[]},{"key":"bave4","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"3qrq5","text":" ","type":"atomic","depth":0,"inlineStyleRanges":[{"style":"bold","offset":3,"length":7},{"style":"bold","offset":15,"length":10},{"style":"bold","offset":30,"length":6},{"style":"sub","offset":45,"length":1},{"style":"sub","offset":48,"length":1},{"style":"sub","offset":86,"length":1},{"style":"sub","offset":89,"length":1},{"style":"sub","offset":214,"length":1}],"entityRanges":[{"key":0,"offset":0,"length":1}],"data":[]},{"key":"61daf","text":"Dissolve in water, bring up to the desired volume, and pH to 7.4 with 10N NaOH.","type":"ordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"f7qs","text":"Measure osmolarity (acceptable range is 295-310 Osm/L).","type":"ordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"26erb","text":"Make ahead of time and store at 4°C.","type":"ordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"6tedl","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"7j043","text":"This buffer was originally developed for dissociating neurons and described in:","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"1npo","text":"Carter BC, Bean BP. Sodium entry during action potentials of mammalian neurons: incomplete inactivation and reduced metabolic efficiency in fast-spiking neurons.Neuron. 2009;64(6):898–909. doi:10.1016/j.neuron.2009.12.011","type":"unstyled","depth":0,"inlineStyleRanges":[{"style":"italic","offset":161,"length":6}],"entityRanges":[],"data":[]},{"key":"9dvh5","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"86ca","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"3monc","text":"WB + 5% Kollidon VA64:","type":"unstyled","depth":0,"inlineStyleRanges":[{"style":"bold","offset":0,"length":22}],"entityRanges":[],"data":[]},{"key":"2qt0o","text":"Place 5 grams of Kollidon VA64 for every 100 mL WB into a bottle containing a stir bar. Cap loosely. Stir slowly until the Kollidon has dissolved completely.  This can take several hours.  Periodic shaking (with cap tightened) will speed the process.  Do not spin too quickly or over night, as this can cause the solution to turn cloudy (if it does so, discard). Store at 4°C.","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"88op9","text":"","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"972i0","text":"Nuclear Extraction Buffer (NEB):","type":"unstyled","depth":0,"inlineStyleRanges":[{"style":"bold","offset":0,"length":32}],"entityRanges":[],"data":[]},{"key":"htib","text":"Make on the day of the extraction.  1% Triton X-100 in WB+5% Kollidon VA64.  3-5 mLs of NEB is required per sample.  Allow the WB+5% Kollidon VA64 to come to room temperature before adding the Triton X-100 (otherwise it will not go into solution easily). Add Triton and pipette up and down rapidly to mix. Vortex and then place on ice when fully incorporated.","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"fejno","text":" ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"apksv","text":" For each sample you wish to extract you will need the following:","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"6oh26","text":"Clean glass slide and new razor blade, at 4°C","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"53pg7","text":"Dissecting tray, kept at -20°C","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"8e48r","text":"Ruler","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"cphim","text":"3 mL syringe with 26 ½ gauge needle, at 4°C (have a few extra chilled ones on hand in case the first one clogs)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"amu51","text":"4 mL chilled extraction buffer, placed in first well of 6-well plate","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"bsjo","text":"6-well tissue-culture plate, well-bottoms colored, on ice","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"f7t14","text":"~50 mL chilled DB","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"37c35","text":"Diluted Hoechst stain (4 uL Hoechst + 996 DB)","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"e47s2","text":"20 µm Steriflip filter + tube, on ice","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"bsgam","text":"5 µm Pluriselect (yellow) filter plus adaptor (green) + 50 mL tube, on ice","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"5tkqc","text":"4 50 mL tubes, on ice","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"5lp6d","text":"c-Chip Fuchs Rosenthal hemacytometer","type":"unordered-list-item","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"3c7rm","text":" ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"5rat7","text":" ","type":"unstyled","depth":0,"inlineStyleRanges":[],"entityRanges":[],"data":[]},{"key":"cqhn1","text":" ","type":"unstyled","depth":0,"inlineStyleRanges":[],"ent